User Friend::getUser(const DbClientPtr &clientPtr) const {
    static const std::string sql = "select * from user where id = ?";
    Result r(nullptr);
    {
        auto binder = *clientPtr << sql;
        binder << *userId_ << Mode::Blocking >>
            [&r](const Result &result) { r = result; };
        binder.exec();
    }
    if (r.size() == 0)
    {
        throw UnexpectedRows("0 rows found");
    }
    else if (r.size() > 1)
    {
        throw UnexpectedRows("Found more than one row");
    }
    return User(r[0]);
}

void Friend::getUser(const DbClientPtr &clientPtr,
                     const std::function<void(User)> &rcb,
                     const ExceptionCallback &ecb) const
{
    static const std::string sql = "select * from user where id = ?";
    *clientPtr << sql
               << *userId_
               >> [rcb = std::move(rcb), ecb](const Result &r){
                    if (r.size() == 0)
                    {
                        ecb(UnexpectedRows("0 rows found"));
                    }
                    else if (r.size() > 1)
                    {
                        ecb(UnexpectedRows("Found more than one row"));
                    }
                    else
                    {
                        rcb(User(r[0]));
                    }
               }
               >> ecb;
}
std::vector<Friend> Friend::getFriend(const DbClientPtr &clientPtr) const {
    static const std::string sql = "select * from friend where friend_id = ?";
    Result r(nullptr);
    {
        auto binder = *clientPtr << sql;
        binder << *userId_ << Mode::Blocking >>
            [&r](const Result &result) { r = result; };
        binder.exec();
    }
    std::vector<Friend> ret;
    ret.reserve(r.size());
    for (auto const &row : r)
    {
        ret.emplace_back(Friend(row));
    }
    return ret;
}

void Friend::getFriend(const DbClientPtr &clientPtr,
                       const std::function<void(std::vector<Friend>)> &rcb,
                       const ExceptionCallback &ecb) const
{
    static const std::string sql = "select * from friend where friend_id = ?";
    *clientPtr << sql
               << *userId_
               >> [rcb = std::move(rcb)](const Result &r){
                   std::vector<Friend> ret;
                   ret.reserve(r.size());
                   for (auto const &row : r)
                   {
                       ret.emplace_back(Friend(row));
                   }
                   rcb(ret);
               }
               >> ecb;
}
